import os
import hashlib

class VersionControlSystem:
    def __init__(self):
        self.repo = {}

    def get_file_hash(self, file_path):
        with open(file_path, "rb") as f:
            contents = f.read()
            return hashlib.sha256(contents).hexdigest()

    def commit(self, file_path):
        file_hash = self.get_file_hash(file_path)

        if file_path in self.repo:
            if self.repo[file_path] != file_hash:
                print("Changes detected, please commit again.")
                return
        else:
            self.repo[file_path] = file_hash
            print("File has been committed.")
