@app.route("/")
def home():
    return render_template("home.html")

@app.route("/request_callback", methods=["POST"])
def request_callback():
    phone = request.form.get("phone")
    time = request.form.get("time")

    template = f"""
    <h3>Callback Request Received</h3>
    <p>Thank you for your callback request!</p>
    <p>We will call you at <b>{time}</b> on <b>{phone}</b>.</p>
    """

    return template

def create_account(username, password):
    if len(username) < 5:
        print("Username must be at least 5 characters.")
        return False
    elif username in ["admin","root","sql"]:
        print("Username not allowed.")
        return False
    elif password == "password":
        print("Account created!")
        return True
    elif len(password) < 8:
        print("Password must be at least 8 characters.")
        return False
    else:
        return True

